+        return Err(CommandError::InvalidInteger);
+    }
+    if slen == 1 && arg[0] == b'0' {
+        return Ok(0);
+    }
+
+    let mut p = 0;
+    let negative = arg[0] == b'-';
+    if negative {
+        p += 1;
+        if p == slen {
+            return Err(CommandError::InvalidInteger);
+        }
+    }
+
+    if arg[p] >= b'1' && arg[p] <= b'9' {
+        let mut v: u64 = (arg[p] - b'0') as u64;
+        p += 1;
+        while p < slen {
+            let b = arg[p];
+            if b.is_ascii_digit() {
+                if v > (u64::MAX / 10) {
+                    return Err(CommandError::InvalidInteger);
+                }
+                v *= 10;
+                let digit = (b - b'0') as u64;
+                if v > (u64::MAX - digit) {
+                    return Err(CommandError::InvalidInteger);
+                }
+                v += digit;
+                p += 1;
+            } else {
+                return Err(CommandError::InvalidInteger);
+            }
+        }
+
+        if negative {
+            let limit = (i64::MIN as u64).wrapping_neg();
+            if v > limit {
+                return Err(CommandError::InvalidInteger);
+            }
+            return Ok(v.wrapping_neg() as i64);
+        } else {
+            if v > i64::MAX as u64 {
+                return Err(CommandError::InvalidInteger);
+            }
+            return Ok(v as i64);
+        }
+    }
+
